// Get GitHub file names from List files from repo
const githubFiles = $('List files from repo').all().map(i => i.json.name).filter(Boolean);

// Get n8n workflow names directly from Retrieve workflows node
const n8nWorkflows = $('Retrieve workflows').all().map(i => i.json.name + '.json');

// Safety abort if either list is empty
if (githubFiles.length === 0) {
  throw new Error('Safety abort: GitHub file list is empty.');
}
if (n8nWorkflows.length === 0) {
  throw new Error('Safety abort: n8n workflow list is empty. Refusing to delete anything.');
}

// Only delete files that don't exist in n8n anymore
const filesToDelete = githubFiles.filter(f => !n8nWorkflows.includes(f));

if (filesToDelete.length === 0) {
  return [{ json: { skipped: true, reason: 'Nothing to delete' } }];
}

return filesToDelete.map(f => ({ json: { path: f, skipped: false } }));

